  ('judicial-f0899a01-moex-00156', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲計畫偷取某豪宅保險箱中的鑽石，雖有把握能順利開啟保險箱，但因豪宅警備森嚴，仍怕有所閃失。女 友乙知悉後，提供一把萬能鑰匙給甲，行竊當天，甲使用該萬能鑰匙順利開啟保險箱，取出鑽石後離去。 有關乙之刑責，下列敘述何者正確？', '["成立竊盜未遂罪之幫助犯", "成立竊盜未遂罪之教唆犯", "成立竊盜既遂罪之幫助犯", "成立竊盜既遂罪之間接正犯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00157', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲在夜市裡欲扒竊皮夾，鎖定一對相談甚歡的乙男與丙女，自後方撞上該乙男，並隨手扒走乙男口袋中的 皮夾。甲越過乙男欲從前方離開現場時，才發現乙男旁邊的丙女是自己的女朋友，一時氣憤暴打乙男之後， 攜帶乙男的錢包離去。下列敘述何者正確？', '["甲犯侵占脫離遺失物罪", "甲犯強盜罪", "甲犯準強盜罪", "甲犯竊盜罪、傷害罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00158', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲為某大學校友會會長兼財務長，校友會章程明訂經費來自於會費繳納與校友捐款，並規定經費應用於在 校學生急難救助、學生獎學金、校友會活動等公益事項。甲因投資失利，將校友會所收會費現金存入自己 帳戶，據為己有。甲應成立何罪？', '["第320條竊盜罪", "第339條詐欺罪", "第336條公益侵占罪", "第337條侵占脫離遺失物罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00159', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '依實務見解，關於賭博罪之敘述，下列何者正確？', '["個人透過網際網路線上參與賭博，亦成立賭博罪", "架設網站供人賭博財物，非屬提供賭博場所", "利用電話傳真機供人聯絡下注，非屬供給賭博場所或聚眾賭博", "當場賭博之器具或財物，限於犯罪行為人所有，始得沒收"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00160', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '下列何者不成立詐欺罪？', '["自始無付錢意思而在餐館白吃白喝", "冒稱自己為小開而向他人求婚", "自始無付錢意思而搭計程車", "車商不告知買主所購買之車輛曾遭重大事故"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00161', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '關於擄人勒贖罪之敘述，下列何者錯誤？', '["擄人勒贖罪有處罰預備犯之規定", "犯意圖勒贖而擄人之罪，未經取贖而釋放被害人者，應減輕其刑", "犯意圖勒贖而擄人之罪，取贖後而釋放被害人者，得減輕其刑", "犯意圖勒贖而擄人之罪而使人受輕傷者，有加重其刑之規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00162', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲與乙嬉鬧中，甲不慎抓到乙臉上配戴的眼鏡，乙眼鏡掉落地上後，造成鏡片破裂及鏡架斷裂之結果。甲 應構成何罪名？', '["過失傷害罪", "毀損罪", "過失毀損罪", "不構成犯罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00163', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-0f9358e7', 'sub-judicial-f0899a01-03', NULL, 'essay', '當事人甲不服臺灣高等法院民事判決，向最高法院提起上訴，甲認為足
